$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8
Write-Host "Applying role & valuation changes..." -ForegroundColor Cyan

$p = "$base\AssetManagement.Domain\Entities\StageDefinition.cs"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: StageDefinition.cs" -ForegroundColor Green

$p = "$base\AssetManagement.Web\Controllers\ValuationController.cs"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: ValuationController.cs" -ForegroundColor Green

$p = "$base\AssetManagement.Web\Views\Valuation\Evaluate.cshtml"
$d = Split-Path $p
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: Evaluate.cshtml" -ForegroundColor Green

# Fix Details.cshtml role variables
$dp = "$base\AssetManagement.Web\Views\Asset\Details.cshtml"
$dc = [System.IO.File]::ReadAllText($dp, $enc)
$oldR = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String("ICAgIGJvb2wgaXNWYWx1YXRvciAgICAgPSByb2xlcy5Db250YWlucygiVmFsdWF0b3IiKSAgICAgfHwgaXNTdXBlckFkbWluOwogICAgYm9vbCBpc1NhbGVzICAgICAgICA9IHJvbGVzLkNvbnRhaW5zKCJTYWxlcyIpICAgICAgICB8fCBpc1N1cGVyQWRtaW47"))
$newR = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String("ICAgIGJvb2wgaXNWYWx1YXRvciAgICAgPSByb2xlcy5Db250YWlucygiTWFya2V0aW5nIikgfHwgcm9sZXMuQ29udGFpbnMoIkZpbmFuY2UiKSB8fCByb2xlcy5Db250YWlucygiTGVnYWwiKSB8fCBpc1N1cGVyQWRtaW47CiAgICBib29sIGlzU2FsZXMgICAgICAgID0gcm9sZXMuQ29udGFpbnMoIk1hcmtldGluZyIpICAgfHwgaXNTdXBlckFkbWluOw=="))
if ($dc.Contains($oldR)) {
    $dc = $dc.Replace($oldR, $newR)
    # Fix DataEntry to Legal in edit button
    $dc = $dc.Replace('roles.Contains("DataEntry") || isSuperAdmin', 'roles.Contains("Legal") || isSuperAdmin')
    [System.IO.File]::WriteAllText($dp, $dc, $enc)
    Write-Host "  OK: Details.cshtml roles updated" -ForegroundColor Green
} else {
    Write-Host "  WARN: Details roles pattern not found - updating manually" -ForegroundColor Yellow
    $dc = $dc.Replace('roles.Contains("Valuator")', 'roles.Contains("Marketing") || roles.Contains("Finance") || roles.Contains("Legal")')
    $dc = $dc.Replace('roles.Contains("Sales")', 'roles.Contains("Marketing")')
    $dc = $dc.Replace('roles.Contains("DataEntry") || isSuperAdmin', 'roles.Contains("Legal") || isSuperAdmin')
    [System.IO.File]::WriteAllText($dp, $dc, $enc)
    Write-Host "  OK: Details.cshtml roles updated via fallback" -ForegroundColor Yellow
}

# Fix Index.cshtml - edit button for Legal
$ip = "$base\AssetManagement.Web\Views\Asset\Index.cshtml"
$ic = [System.IO.File]::ReadAllText($ip, $enc)
$ic = $ic.Replace('User.IsInRole("DataEntry") || User.IsInRole("SuperAdmin")', 'User.IsInRole("Legal") || User.IsInRole("SuperAdmin")')
[System.IO.File]::WriteAllText($ip, $ic, $enc)
Write-Host "  OK: Index.cshtml edit button updated" -ForegroundColor Green

cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Build OK! Run SQL cleanup_users_roles.sql in SSMS." -ForegroundColor Green }